// Generated by AI (UnitTest MCP)
//! Tool definitions and dispatch for the Lodestar MCP server.

mod conformance;
mod constitution;
mod design;
mod design_materialization;
mod evidence;
mod executive;
mod knowledge;
mod lifecycle;

use lodestar_core::Lodestar;
use mindleak_session::SessionRegistry;
use serde::Serialize;
use serde_json::{json, Value};

/// The advertised tool list (`tools/list`).
pub fn list() -> Vec<Value> {
    let mut tools = vec![session_definition()];
    tools.extend(constitution::definitions());
    tools.extend(executive::definitions());
    tools.extend(conformance::definitions());
    tools.extend(knowledge::definitions());
    tools.extend(lifecycle::definitions());
    tools.extend(design::definitions());
    tools.extend(design_materialization::definitions());
    tools.extend(evidence::definitions());
    tools.into_iter().map(apply_session_contract).collect()
}

pub fn bind_session(params: &Value, sessions: &SessionRegistry) -> Result<Value, String> {
    let name = params.get("name").and_then(Value::as_str).unwrap_or("");
    let mut bound = params.clone();
    let args = bound
        .get_mut("arguments")
        .and_then(Value::as_object_mut)
        .ok_or_else(|| "tool arguments must be an object".to_string())?;
    if name == "open_session" {
        let token = args
            .get("session_id")
            .and_then(Value::as_str)
            .ok_or_else(|| "missing required string arg: session_id".to_string())?;
        let identity = sessions.open_session(token)?;
        args.insert("resolved_agent".to_string(), json!(identity.agent_id));
        return Ok(bound);
    }
    if requires_session(name) {
        let token = args
            .get("session_id")
            .and_then(Value::as_str)
            .ok_or_else(|| "missing required string arg: session_id".to_string())?;
        let identity = sessions.resolve(token)?;
        args.insert("agent".to_string(), json!(identity.agent_id));
        if let Some(evidence) = args.get_mut("evidence").and_then(Value::as_object_mut) {
            evidence.insert("agent_id".to_string(), json!(identity.agent_id));
        }
    }
    Ok(bound)
}

/// Dispatch a `tools/call`. Returns the MCP `content` object or an error string.
pub fn call(engine: &Lodestar, params: &Value) -> Result<Value, String> {
    let name = params.get("name").and_then(Value::as_str).unwrap_or("");
    let args = params.get("arguments").cloned().unwrap_or(Value::Null);

    if name == "open_session" {
        return ok(&json!({ "agent_id": req_str(&args, "resolved_agent")? }));
    }

    if let Some(result) = constitution::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = executive::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = conformance::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = knowledge::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = lifecycle::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = design::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = design_materialization::dispatch(engine, name, &args) {
        return result;
    }

    if let Some(result) = evidence::dispatch(engine, name, &args) {
        return result;
    }

    Err(format!("unknown tool: {name}"))
}

fn session_definition() -> Value {
    json!({
        "name": "open_session",
        "description": "Register one client-minted 128-bit session id and return its stable cross-plane agent identity. Reuse the same session_id on every identity-bearing tool call and after server restarts.",
        "inputSchema": {
            "type": "object",
            "properties": {
                "session_id": { "type": "string", "pattern": "^[0-9a-f]{32}$" }
            },
            "required": ["session_id"]
        }
    })
}

fn requires_session(name: &str) -> bool {
    matches!(
        name,
        "register_design"
            | "claim_task"
            | "renew_lease"
            | "complete_task"
            | "release_task"
            | "recover_claim"
            | "ask_question"
            | "pause_task"
            | "resume_task"
            | "check_conformance"
    )
}

fn apply_session_contract(mut tool: Value) -> Value {
    let name = tool.get("name").and_then(Value::as_str).unwrap_or("");
    if !requires_session(name) {
        return tool;
    }
    if let Some(properties) = tool
        .get_mut("inputSchema")
        .and_then(|schema| schema.get_mut("properties"))
        .and_then(Value::as_object_mut)
    {
        properties.remove("agent");
        properties.insert(
            "session_id".to_string(),
            json!({
                "type": "string",
                "pattern": "^[0-9a-f]{32}$",
                "description": "Session id previously registered with open_session."
            }),
        );
    }
    if let Some(required) = tool
        .get_mut("inputSchema")
        .and_then(|schema| schema.get_mut("required"))
        .and_then(Value::as_array_mut)
    {
        required.retain(|value| value != "agent");
        if !required.iter().any(|value| value == "session_id") {
            required.push(json!("session_id"));
        }
    } else if let Some(schema) = tool.get_mut("inputSchema").and_then(Value::as_object_mut) {
        schema.insert("required".to_string(), json!(["session_id"]));
    }
    tool
}

// ---- helpers ---------------------------------------------------------------

pub(super) fn req_str<'a>(args: &'a Value, key: &str) -> Result<&'a str, String> {
    args.get(key)
        .and_then(Value::as_str)
        .ok_or_else(|| format!("missing required string arg: {key}"))
}

pub(super) fn opt_str(args: &Value, key: &str) -> Option<String> {
    args.get(key)
        .and_then(Value::as_str)
        .filter(|s| !s.is_empty())
        .map(|s| s.to_string())
}

pub(super) fn optional_string_arg(args: &Value, key: &str) -> Result<Option<String>, String> {
    match args.get(key) {
        None | Some(Value::Null) => Ok(None),
        Some(Value::String(value)) if !value.trim().is_empty() => Ok(Some(value.clone())),
        Some(Value::String(_)) => Err(format!("argument {key} must not be empty")),
        Some(_) => Err(format!("argument {key} must be a string")),
    }
}

pub(super) fn i64_arg(args: &Value, key: &str, default: i64) -> i64 {
    args.get(key).and_then(Value::as_i64).unwrap_or(default)
}

pub(super) fn bool_arg(args: &Value, key: &str, default: bool) -> bool {
    args.get(key).and_then(Value::as_bool).unwrap_or(default)
}

pub(super) fn str_array(args: &Value, key: &str) -> Vec<String> {
    args.get(key)
        .and_then(Value::as_array)
        .map(|a| {
            a.iter()
                .filter_map(|v| v.as_str().map(|s| s.to_string()))
                .collect()
        })
        .unwrap_or_default()
}

pub(super) fn ok<T: Serialize>(value: &T) -> Result<Value, String> {
    let body = serde_json::to_string_pretty(value).map_err(|e| e.to_string())?;
    text(body)
}

/// A tool result that renders as Markdown in chat while keeping the structured
/// JSON in `structuredContent` for programmatic consumers (the extension client
/// and agents). VS Code renders `content`; machine consumers read
/// `structuredContent`, so display can be rich without breaking parsers.
pub(super) fn rendered<T: Serialize>(
    markdown: impl Into<String>,
    value: &T,
) -> Result<Value, String> {
    let structured = serde_json::to_value(value).map_err(|e| e.to_string())?;
    Ok(json!({
        "content": [{ "type": "text", "text": markdown.into() }],
        "structuredContent": structured,
    }))
}

pub(super) fn text(body: String) -> Result<Value, String> {
    Ok(json!({ "content": [{ "type": "text", "text": body }] }))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn tool_contract_requires_evidence_and_exposes_binding_mode() {
        let tools = list();
        let complete = tools
            .iter()
            .find(|tool| tool["name"] == "complete_task")
            .unwrap();
        assert!(complete["inputSchema"]["required"]
            .as_array()
            .unwrap()
            .iter()
            .any(|value| value == "evidence"));
        let link = tools
            .iter()
            .find(|tool| tool["name"] == "link_goal_to_code")
            .unwrap();
        assert_eq!(
            link["inputSchema"]["properties"]["mode"]["default"],
            "governed"
        );
        let create = tools
            .iter()
            .find(|tool| tool["name"] == "create_task")
            .unwrap();
        assert!(create["inputSchema"]["properties"]["blocked_by"].is_object());
    }

    #[test]
    fn tools_list_exposes_no_duplicate_names() {
        // Regression: ADR-0022 copy-pasted the `consolidate` definition, so
        // tools/list advertised two identical entries and MCP clients saw an
        // ambiguous, duplicated verb. Every advertised tool name must be unique.
        let tools = list();
        let mut names: Vec<&str> = tools
            .iter()
            .map(|tool| tool["name"].as_str().unwrap())
            .collect();
        let total = names.len();
        names.sort_unstable();
        names.dedup();
        assert_eq!(names.len(), total, "duplicate tool name in tools/list");

        for tool in tools.iter().filter(|tool| {
            tool["inputSchema"]["properties"]["session_id"].is_object()
                && tool["name"] != "open_session"
        }) {
            assert!(tool["inputSchema"]["properties"]["agent"].is_null());
            assert!(!tool["inputSchema"]["required"]
                .as_array()
                .unwrap()
                .iter()
                .any(|value| value == "agent"));
        }
    }
}
